/* ================== DATA MODEL ================== */
const SECTIONS = {
  en: { label: "English Section" },
  fr: { label: "French Section" }
};

// Small recognizable icon shown next to a subject's name wherever it appears in the
// UI (stepper, breadcrumb, Reports columns, user permission checkboxes, etc.). Keyed
// on the "base" subject name so English O.L./A.L. and French O.L./A.L. share one icon.
const SUBJECT_ICONS = {
  'Arabic':'ع','English':'🔤','Mathematics':'📐','Science':'🔬','Integrated Sciences':'🔬',
  'Social Studies':'🌍','History':'🏛️','Philosophy':'🧠','Religion':'🕌','Ch-Religion':'✝️',
  'French':'🇫🇷','German':'🇩🇪','Art':'🎨','ICT':'💻'
};
function subjectIcon(subject){
  if(!subject) return '';
  const base = subject.replace(/\s*(O\.L\.|A\.L\.)$/,'').trim();
  return SUBJECT_ICONS[base] || '📘';
}
function subjectWithIcon(subject){
  return subject ? `${subjectIcon(subject)} ${subject}` : subject;
}

const STAGES = {
  primary:  { label: "Primary Stage", grades: [
      {id:'g1', label:'Grade 1'},
      {id:'g2', label:'Grade 2'},
      {id:'g3', label:'Grade 3'},
      {id:'g4', label:'Grade 4'},
      {id:'g5', label:'Grade 5'},
      {id:'g6', label:'Grade 6'}
    ],
    subjects: ["Arabic","English O.L.","Mathematics","Science","Social Studies","English A.L.","Religion","Ch-Religion","French","German","ICT"]
  },
  prep:     { label: "Prep Stage", grades: [
      {id:'g7', label:'Grade 7'},
      {id:'g8', label:'Grade 8'},
      {id:'g9', label:'Grade 9'}
    ],
    subjects: ["Arabic","English O.L.","Mathematics","Science","Social Studies","English A.L.","Religion","Ch-Religion","French","German","Art","ICT"]
  },
  secondary:{ label: "Secondary Stage", grades: [
      {id:'g10', label:'Grade 10'},
      {id:'g11', label:'Grade 11'},
      {id:'g12', label:'Grade 12'}
    ],
    subjects: ["Arabic","English O.L.","Mathematics","Integrated Sciences","History","Philosophy","English A.L.","Religion","Ch-Religion","French O.L.","German O.L.","French A.L.","German A.L.","ICT"]
  }
};

// Grade 12 (3rd Secondary) uses simplified subject list for class-level mark entry
const G12_SUBJECTS_EN = ["Arabic","English","Physics","Chemistry","Pure Mathematics","Applied Mathematics","Biology","History","Geography","Statistics"];
const G12_SUBJECTS_FR = ["Arabic","French","Physics","Chemistry","Pure Mathematics","Applied Mathematics","Biology","History","Geography","Statistics"];

// Grade 12 End-of-Year Mark Entry is recorded for the WHOLE GRADE in a single table (one row
// per student, one column per subject) instead of picking one subject at a time. Each subject
// has its own maximum full mark:
const G12_SUBJECT_MAX = {
  'Arabic': 80, 'English': 60, 'French': 60, 'Physics': 60, 'Chemistry': 60,
  'Pure Mathematics': 30, 'Applied Mathematics': 30,
  'Biology': 60, 'History': 60, 'Geography': 60, 'Statistics': 60
};
function g12SubjectMax(subject){ return G12_SUBJECT_MAX[subject] || 0; }
// "Math Total" column = Pure Mathematics + Applied Mathematics (computed, not directly editable).
// The overall "Total" column (Max. 320) is Arabic + English/French + Physics + Chemistry + Math
// Total (80+60+60+60+60=320) — Biology, History, Geography and Statistics are recorded in the
// table but are NOT counted toward this Total (they're extra/elective subjects per student track).
const G12_CORE_TOTAL_SUBJECTS = ['Arabic','English','French','Physics','Chemistry','Pure Mathematics','Applied Mathematics'];
const G12_TOTAL_MAX = 320;

// Three extra columns shown at the very end of the Grade 12 table, after Total/Percentage/Grade.
// Recorded the same way as any other Grade 12 subject (same scores bucket), but kept OUT of
// G12_CORE_TOTAL_SUBJECTS so they never affect the Total/Percentage/Grade calculation above.
const G12_EXTRA_SUBJECTS = ["Religion","Second Language","Civics"];
const G12_EXTRA_SUBJECT_MAX = { 'Religion':40, 'Second Language':40, 'Civics':10 };
// Religion has its own pass mark (out of 40) shown as a Pass/Fail hint next to the score.
const G12_RELIGION_PASS_MARK = 28;

// French Section-specific subject mappings
const FRENCH_SECTION_SUBJECTS = {
  primary:  { label: "Primary Stage",
    subjects: ["Arabic","French O.L.","Mathematics","Science","Social Studies","French A.L.","Religion","Ch-Religion","English","ICT"]
  },
  prep:     { label: "Prep Stage",
    subjects: ["Arabic","French O.L.","Mathematics","Science","Social Studies","French A.L.","Religion","Ch-Religion","English","Art","ICT"]
  },
  secondary:{ label: "Secondary Stage",
    subjects: ["Arabic","French O.L.","Mathematics","Integrated Sciences","History","Philosophy","French A.L.","Religion","Ch-Religion","English O.L.","English A.L.","ICT"]
  }
};

// Primary Grades 1 & 2 don't take Social Studies or ICT (unlike Grades 3-6, which share
// the standard Primary Stage subject list) — dropped from every subject list wherever a
// grade is known (grading, certificates, attendance, dashboards, permissions, bulk import).
function isJuniorPrimaryGrade(stageKey, gradeId){
  return stageKey==='primary' && (gradeId==='g1' || gradeId==='g2');
}
function filterSubjectsForGrade(subjects, stageKey, gradeId){
  if(!isJuniorPrimaryGrade(stageKey, gradeId)) return subjects;
  return subjects.filter(sub=> sub!=='Social Studies' && sub!=='ICT');
}

// Helper function to get correct subjects based on section. gradeId is optional — pass it
// whenever the calling context already knows the grade so Grade 1/2 Primary can drop
// Social Studies/ICT; omitted call sites keep returning the full Stage-level list.
function getSubjectsForStageAndSection(stageKey, sectionId, gradeId){
  const subjects = sectionId === 'fr'
    ? (FRENCH_SECTION_SUBJECTS[stageKey] ? FRENCH_SECTION_SUBJECTS[stageKey].subjects : STAGES[stageKey].subjects)
    : STAGES[stageKey].subjects;
  return gradeId ? filterSubjectsForGrade(subjects, stageKey, gradeId) : subjects;
}

// Get subjects for a specific grade (handles Grade 12 separately)
function getSubjectsForGrade(stageKey, gradeId, sectionId){
  if(stageKey === 'secondary' && gradeId === 'g12'){
    return sectionId === 'fr' ? G12_SUBJECTS_FR : G12_SUBJECTS_EN;
  }
  return getSubjectsForStageAndSection(stageKey, sectionId, gradeId);
}

// Used to order the Student Database list: English Section before French Section,
// and within each, Grade 1 → Grade 11 ascending (built from STAGES' own order, so
// Primary → Prep → Secondary already yields g1..g11 in the right sequence).
const SECTION_ORDER = { en:0, fr:1 };
const GRADE_ORDER = {};
// Flat lookup of every Grade id -> label across all Stages, used wherever a Grade needs to
// be labelled without also needing the Stage/Section scoping (e.g. Exam Schedule titles).
const GRADE_LABEL_BY_ID = {};
const ALL_GRADE_IDS = [];
(function(){
  let i = 0;
  ['primary','prep','secondary'].forEach(stageKey=>{
    STAGES[stageKey].grades.forEach(g=>{ GRADE_ORDER[g.id] = i++; GRADE_LABEL_BY_ID[g.id] = g.label; ALL_GRADE_IDS.push(g.id); });
  });
})();

// Absence tab keeps its OWN independent copies of the Section/Stage/Grade lists.
// These start out identical to SECTIONS/STAGES above, but editing one set (e.g. adding a
// section/stage/grade here or in the Grade Book lists) will NOT affect the other — they are
// completely separate lists, only the selected VALUES (state vs attState) were already independent.
const ATT_SECTIONS = JSON.parse(JSON.stringify(SECTIONS));
const ATT_STAGES = JSON.parse(JSON.stringify(STAGES));

let state = { termPeriod:null, section:null, stage:null, grade:null, term:null, academicTerm:null, subject:null,
  dashboardTerm:null, dashboardMode:null, dashboardSection:null, dashboardStage:null, dashboardGrade:null, dashboardClassroom:null, dashboardStudent:null,
  examsTerm:null, examsMode:null, examsSection:null, examsStage:null, examsGrade:null, examsClassroom:null, examsSubject:null,
  perfTerm:null, perfCycle:null, perfCategory:null };

// Top Performance / At Risk keeps its own independent Section/Stage/Grade/Class filter,
// fully separate from the Grade Book's state. Each Term × Cycle × Category combination gets
// its OWN filter (keyed below) so switching between, say, "Term 1 Cycle 1 Top Performance"
// and "Term 1 Cycle 1 At Risk" never carries the Section/Stage/Grade/Class choice over.
let perfFilterStates = {};
function perfFilterKey(){ return `${state.perfTerm}|${state.perfCycle}|${state.perfCategory}`; }
function getPerfFilterState(){
  const k = perfFilterKey();
  if(!perfFilterStates[k]) perfFilterStates[k] = { __isPerfFilter:true, section:null, stage:null, grade:null, term:null };
  return perfFilterStates[k];
}
// Absence tab keeps its own independent selections (Academic Term / Section / Stage / Grade / Class),
// completely separate from the Grade Book tab's selections above.
let attState = { termPeriod:null, section:null, stage:null, grade:null, term:null, subject:null, academicTerm:null };
let openStep = null;
let currentView = 'database';

/* ================== Central Ticker ==================
   Consolidates every recurring background poll (class alert watcher, Grade Entry
   Control re-check, header quick widgets, presence heartbeat/poll, birthday widget,
   clock, weather) into ONE setInterval that ticks once a second, instead of each
   feature running its own independent setInterval. A feature calls registerTicker()
   with its own effective interval (in ms) and callback; this fires that callback every
   time roughly that many seconds have elapsed, by accumulating on each 1s tick — so
   every feature keeps the exact same cadence it had before, but only one timer is ever
   actually running in the browser, no matter how many features are active. Much lighter
   on a tab left open for hours than the previous ~7 independent timers.
   registerTicker(id, intervalMs, fn, {runImmediately:false}) — by default the task's
   first firing happens after one full intervalMs (matching plain setInterval behavior);
   pass runImmediately:true to fire on the very next 1s tick instead. */
const tickerTasks = {}; // id -> { intervalMs, fn, elapsed }
let tickerHandle = null;
function registerTicker(id, intervalMs, fn, opts){
  tickerTasks[id] = { intervalMs, fn, elapsed: (opts && opts.runImmediately) ? intervalMs : 0 };
  if(!tickerHandle){
    tickerHandle = setInterval(()=>{
      Object.keys(tickerTasks).forEach(taskId=>{
        const task = tickerTasks[taskId];
        if(!task) return;
        task.elapsed += 1000;
        if(task.elapsed >= task.intervalMs){
          task.elapsed = 0;
          try{ task.fn(); }catch(err){ console.warn(`Ticker task "${taskId}" failed:`, err); }
        }
      });
    }, 1000);
  }
}
function unregisterTicker(id){ delete tickerTasks[id]; }


// students[classKey] = [{id, displayId, name, classroom, lang2}]
let students = {};
// A student whose Notes field is exactly "TC" (case-insensitive, ignoring surrounding
// spaces) is kept in the Students Database list itself, but is hidden from every other
// list in the app (Grade Book, Attendance, Report Cards/Certificates, Class Lists,
// Statistics, Performance/Ranking, Parent Dashboard, Exams Analysis, etc.).
function isTCStudent(s){
  return !!(s && typeof s.notes === 'string' && s.notes.trim().toUpperCase() === 'TC');
}
function visibleRoster(list){
  return (list || []).filter(s => !isTCStudent(s));
}
// scores[subjKey] = { studentId: {...} } — subjKey includes the term, so each term keeps its own scores
let scores = {};
// Auditable grade changes and scheduled report definitions.  They live beside the
// rest of the shared school data and are synced through the meta document below.
let gradeChangeHistory = [];
let scheduledReports = [];
const GRADE_HISTORY_MAX = 5000;
let studentIdCounter = 1;
// attendance[classKey|classroom|termPeriod|term|subject|academicTerm] = { start, end, dates:[...], records:{studentId:{dateStr:true}} }
// Each Term (1st/2nd) x Month (1st/2nd) combination is its own independent attendance table —
// selected via the Attendance tab's own stepper, exactly like the Grade Book's Mark Entry step.
let attendance = {};
// approvedLeave[classKey|classroom|termPeriod|term|subject|academicTerm] = { records:{studentId:{dateStr:true}} }
// Uses the EXACT SAME key/date-range as `attendance` above (same class/subject/month table,
// same dates) — it is not a separate table with its own Start/End, it's a second layer of
// records on top of the Absence table. Any date marked here for a student:
//   1) is shown as a locked "L" cell in the Absence table instead of a checkbox, and is
//      NOT counted in that student's absence total, and
//   2) if that student already had an absence (checkbox) recorded for that exact day,
//      marking it as Approved Leave cancels that absence for that day.
let approvedLeave = {};
// Which sub-tab of the "Absence (Subjects)" tab is currently showing — 'absence' (the
// original attendance-taking table) or 'summary'. 'leave' (the Approved Leave table) used to
// live here too as a third sub-tab, but Approved Leave now has its own separate top-level nav
// item (see ensureApprovedLeaveNavTab/openApprovedLeaveTab below) — attSubView can still be set
// to 'leave' internally (renderAttendanceTable() still dispatches on it) since that's what
// openApprovedLeaveTab() sets before rendering, it's just no longer reachable from the
// Absence (Subjects) tab's own dropdown.
let attSubView = 'absence';

