const fbApp = firebase.initializeApp(firebaseConfig);
const fbDb  = firebase.firestore();
// ---- Storage layout (split, since 2026-07) ----
// Grade Book data (students/scores/attendance/approvedLeave) used to live entirely in ONE
// document ('gradebook/main') — every Save/pull/live-update touched the WHOLE school's data
// at once, no matter how small the actual edit was. That made the manual Save button get
// slower and slower as the school's data grew, since every click read + merged + rewrote
// everything, every time.
// It is now split by class (classKey = "section|stage|grade", the same key `students` was
// already keyed by internally) into its own small document per class, under the
// 'gradebook_classes' collection. A Save now only reads/writes the class(es) that actually
// changed (see computeDirtyClassKeys() below) plus the small shared 'meta' document —
// instead of the entire school every time.
// FB_DOC_REF ('gradebook/main') is kept only as the OLD document, read-only, used solely by
// migrateMainDocToClassDocs() to do a one-time split of whatever was last saved there. Nothing
// else reads or writes it anymore — it is never deleted, so it stays as a safety-net backup.
const FB_DOC_REF = fbDb.collection('gradebook').doc('main');
// Small shared document: everything that ISN'T tied to one class (activity log, term/exam
// schedule config, bell times, admin structure, blocked students, Grade 3 flexible maxima,
// grade-entry lock rules, presence bucket id, report card / exam schedule release dates).
const FB_META_DOC_REF = fbDb.collection('gradebook').doc('meta');
// One document per class (id built from classKey by classDocId() below) holding just that
// class's slice of students/scores/attendance/approvedLeave.
const FB_CLASSES_COL = fbDb.collection('gradebook_classes');
// Teachers Database and Manage Users (split into Staff vs Parents/Students) each live in
// their own document now, instead of inside the single 'main' document above. This means
// editing a Teacher, or adding/editing a Parent/Student account, no longer reads or writes
// Students/Scores/Attendance at all — each domain is pushed and pulled independently.
// Parents/Students get their own document (separate from Staff) because that list is
// expected to grow far larger (one row per family) than the handful of Staff accounts,
// so it should never share a size/contention budget with Teacher/HOD/Admin accounts.
const FB_TEACHERS_DOC_REF = fbDb.collection('gradebook').doc('teachers');
const FB_STAFF_USERS_DOC_REF = fbDb.collection('gradebook').doc('staffUsers');
const FB_PARENT_USERS_DOC_REF = fbDb.collection('gradebook').doc('parentUsers');

// ✅ تتبع ما إذا كانت بيانات المدرسين قد تم تحديثها من Firestore
let teachersUpdatedFlag = false;

const GITHUB_CFG_KEY = 'gradesSystemFirebaseCfg_v1'; // kept name for minimal disruption to storage; holds { enabled }

// Tracks when this browser last actually received confirmed data from Firestore (a
// successful pull OR a live-listener update) — kept in localStorage so it survives a
// reload instead of resetting to "Never" every time the page opens. Lets an Admin
// glance at the header pill and confirm everyone is looking at the same version,
// instead of just knowing sync is "on" with no sense of how fresh the data actually is.
const LAST_SYNC_LS_KEY = 'lastFirestoreSyncAt_v1';
function recordLastSyncTime(){
  const now = Date.now();
  try{ localStorage.setItem(LAST_SYNC_LS_KEY, String(now)); }catch(err){}
  return now;
}
function getLastSyncTime(){
  try{ const raw = localStorage.getItem(LAST_SYNC_LS_KEY); return raw ? parseInt(raw,10) : null; }
  catch(err){ return null; }
}
// "2:45 PM" for today, "Jul 14, 2:45 PM" for any earlier day — short enough for an
// inline badge while still being unambiguous once a few days have passed.
function formatSyncTimeLabel(ts){
  if(!ts) return null;
  const d = new Date(ts);
  const now = new Date();
  const sameDay = d.toDateString() === now.toDateString();
  const time = d.toLocaleTimeString(undefined, {hour:'numeric', minute:'2-digit'});
  if(sameDay) return time;
  const datePart = d.toLocaleDateString(undefined, {month:'short', day:'numeric'});
  return `${datePart}, ${time}`;
}
let githubConfig = null; // { enabled }
let fbUnsubscribe = null;
let fbApplyingRemote = false; // guard so a remote snapshot doesn't immediately re-trigger a push
let fbLastPushedAt = 0;
// Every push tags the document with a version number one higher than the last version we
// know about (ours or a remote one we've already applied). The live listener only applies an
// incoming snapshot if its version is strictly newer than this. This protects against a slow
// round-trip: if the local push takes a while to echo back (or never lands as an "echo" within
// the old fixed time window) and the person keeps entering grades in the meantime, the stale
// echo/snapshot is recognized as not-newer and is ignored instead of overwriting the freshly
// entered grades still sitting only in memory/localStorage.
// Meta doc's own version counter (activity log / config — see pushMetaDoc/FB_META_DOC_REF).
let knownMetaVersion = 0;
// One version counter per classKey (see pushClassDoc/FB_CLASSES_COL) — a class's own live
// listener recognizes "this is just an echo of my own push" independently of every other
// class's version number.
let knownClassVersions = {};
// Same purpose as knownMetaVersion above, one per newly-split document, so each document's
// live listener can independently recognize "this is just an echo of my own push" without
// depending on the other documents' version numbers.
let knownTeachersVersion = 0;
let knownStaffUsersVersion = 0;
let knownParentUsersVersion = 0;
// Tracks whether ANY edit made via scheduleGithubPush() (users, teachers, bell times, admin
// structure, exam schedules, blocked students, report card/exam releases, etc.) has actually
// finished round-tripping to Firestore yet. Unlike gbUnsavedChanges (which only covers Grade
// Book scores), this covers every other save path in the app, all of which are debounced by
// ~2.5s. Without this flag, closing or hard-refreshing the tab inside that 2.5s window loses
// the edit silently: it looked "saved" locally, but the write never reached the server, and
// the very next page load pulls the older server copy over it.
let pendingFirestorePush = false;
// Same purpose as pendingFirestorePush above, one per newly-split document — kept separate
// so an edit still in flight in one document (e.g. a Teacher edit) doesn't make the merge
// logic for an unrelated document (e.g. Users) defensively distrust the server when it
// doesn't need to.
let pendingTeachersPush = false;
let pendingUsersPush = false;

function loadGithubConfig(){
  try{
    const raw = localStorage.getItem(GITHUB_CFG_KEY);
    githubConfig = raw ? JSON.parse(raw) : { enabled: true }; // sync on by default
  }catch(err){ githubConfig = { enabled: true }; }
}
function persistGithubConfig(){
  try{ localStorage.setItem(GITHUB_CFG_KEY, JSON.stringify(githubConfig)); }
  catch(err){ console.warn('Could not save Firebase sync settings', err); }
}

function githubReady(){ return !!(githubConfig && githubConfig.enabled); }
function githubPullReady(){ return true; } // Firestore doc is always reachable, no credentials needed

function setSyncStatus(state){
  const el = document.getElementById('githubSyncStatus');
  if(!el) return;
  if(!currentUser || currentUser.role!=='admin'){ el.style.display = 'none'; return; }
  if(!githubConfig || !githubConfig.enabled){ el.style.display = 'none'; return; }
  if(state==='synced') recordLastSyncTime();
  const lastSyncTs = getLastSyncTime();
  const lastSyncLabel = formatSyncTimeLabel(lastSyncTs);
  const map = {
    idle:    ['☁ Not synced yet', '#B8B2A0'],
    syncing: ['☁ Syncing…', 'var(--gold-deep)'],
    synced:  [`☁ Synced${lastSyncLabel ? ' · Last: '+lastSyncLabel : ' with Firebase'}`, 'var(--green)'],
    error:   [`⚠ Firebase sync error${lastSyncLabel ? ' · Last synced: '+lastSyncLabel : ''}`, 'var(--red)']
  };
  const [text,color] = map[state] || map.idle;
  el.textContent = text;
  el.title = lastSyncTs ? `Last confirmed sync with Firestore: ${new Date(lastSyncTs).toLocaleString()}` : 'No successful sync yet on this device';
  el.style.color = color;
  el.style.display = 'inline-flex';
  if(state!=='idle') flashSyncBadgeNearEdit(text, color);
}

// Shows a small floating pill at the last-edited cell's position, so whoever is
// entering grades sees the sync outcome right where they're looking instead of
// having to glance up at the header. Skipped if the edit was too long ago (e.g. the
// sync was triggered by something other than a recent grade entry).
function flashSyncBadgeNearEdit(text, color){
  if(!lastEditRect || (Date.now() - lastEditTime) > 15000) return;
  const badge = document.createElement('div');
  badge.className = 'inline-sync-badge';
  badge.textContent = text;
  badge.style.background = color;
  badge.style.left = '12px';
  badge.style.top = (lastEditRect.top + lastEditRect.height/2) + 'px';
  document.body.appendChild(badge);
  requestAnimationFrame(()=> badge.classList.add('show'));
  setTimeout(()=>{
    badge.classList.remove('show');
    setTimeout(()=> badge.remove(), 200);
  }, 1600);
}

/* One-off, everyone-sees-it indicator (unlike setSyncStatus's header pill, which is
   Admin-only) for the very first data pull on page load. Without this, whatever was
   last cached in localStorage renders immediately and the app can look complete —
   or, on a brand-new device with no cache yet, look empty — for however long the
   Firestore round-trip to fetch the real latest data takes, with no sign anything
   is happening in the background. */
function showInitialSyncIndicator(){
  let el = document.getElementById('initialSyncBanner');
  if(!el){
    el = document.createElement('div');
    el.id = 'initialSyncBanner';
    el.innerHTML = `<span class="initial-sync-spinner"></span><span>Loading the latest data…</span>`;
    document.body.appendChild(el);
  }
  requestAnimationFrame(()=> el.classList.add('show'));
}
function hideInitialSyncIndicator(){
  const el = document.getElementById('initialSyncBanner');
  if(!el) return;
  el.classList.remove('show');
  setTimeout(()=>{ const cur = document.getElementById('initialSyncBanner'); if(cur && !cur.classList.contains('show')) cur.remove(); }, 400);
}

// Shared post-apply UI refresh — cheap to call after ANY of the three documents below
// finishes applying, since re-rendering only the currently visible tab is far cheaper
// than the network reads/writes that used to be entangled across documents. Kept as one
// function so all three apply* functions below stay in sync on what gets refreshed.
// Every branch is gated on currentView — a remote change shouldn't rebuild the Student
// Database, Teachers Database, Grade Book table or Attendance workspace while the user
// is sitting on, say, the Dashboard tab; that work happens for free the moment they
// actually switch into one of those tabs (see switchView()).
function refreshUIAfterRemoteChange(){
  saveStateLocalOnly();
  if(currentView==='database') renderDatabaseNow();
  if(currentView==='teachers' && typeof renderTeachersDatabase==='function') renderTeachersDatabase();
  if(currentView==='grades' && typeof renderTable==='function') renderTable();
  if(currentView==='attendance' && typeof renderAttendanceWorkspace==='function') renderAttendanceWorkspace();
  // Re-render the Certificates tab live if a Parent/Student (or Admin) currently has it open,
  // so a newly-released Report Card appears immediately without needing a manual refresh.
  if(currentView==='certReports' && typeof renderCertReportsWorkspace==='function'){
    if(typeof renderCertReportsStepper==='function') renderCertReportsStepper();
    renderCertReportsWorkspace();
  }
  // Mark Entry Report shows live "entered / total" counts pulled straight from `scores` —
  // if it's left open while another device pushes new marks, it needs the same live
  // re-render as Certificates above, or its counts silently go stale.
  if(currentView==='markEntryReport' && typeof renderMarkEntryWorkspace==='function'){
    renderMarkEntryWorkspace();
  }
  if(document.getElementById('reportCardReleaseOverlay') && document.getElementById('reportCardReleaseOverlay').classList.contains('show')){
    renderReportCardReleaseTable();
  }
  if(document.getElementById('examScheduleReleaseOverlay') && document.getElementById('examScheduleReleaseOverlay').classList.contains('show')){
    renderExamScheduleReleaseTable();
  }
  if(currentUser){
    if(isViewerAccountBlocked()){
      showAccountBlockedScreen();
    } else if(document.getElementById('accountBlockedPanel') && document.getElementById('accountBlockedPanel').style.display==='flex'){
      // was blocked, just got unblocked remotely — restore normal navigation
      document.getElementById('mainNav').style.display = '';
      document.getElementById('accountBlockedPanel').style.display = 'none';
      const allowed = firstAllowedTab();
      if(allowed) switchView(allowed);
      else document.getElementById('noAccessPanel').style.display = 'flex';
    }
  }
  updateGradeBookSaveUI();
}

// ---- applyClassPayload(ck, payload): one class's students/scores/attendance/
// approvedLeave — the document written by pushClassDoc(). Only ever touches this ONE
// classKey's slice of the global students/scores/attendance/approvedLeave objects; every
// other class already in memory is left completely untouched.
function applyClassPayload(ck, payload){
  if(!payload) return;
  fbApplyingRemote = true;
  // Same reasoning as the old single-doc version: if this device has Grade Book edits
  // sitting locally that haven't been pushed yet ANYWHERE (gbUnsavedChanges), blindly
  // replacing this class's data would risk silently wiping out an unsaved edit — so keep
  // any key(s) local already has and only let remote fill in ones it's missing. With no
  // pending edits anywhere, it's safe to just replace this class's slice wholesale.
  const hadLocalStudents = Object.prototype.hasOwnProperty.call(students, ck);
  let replacedWholesale;
  if(gbUnsavedChanges){
    if(!hadLocalStudents){ students[ck] = payload.students || []; replacedWholesale = true; }
    else{ replacedWholesale = false; }
  }else{
    students[ck] = payload.students || [];
    replacedWholesale = true;
  }
  mergeOrReplaceClassKeys(scores, ck, payload.scores);
  mergeOrReplaceClassKeys(attendance, ck, payload.attendance);
  mergeOrReplaceClassKeys(approvedLeave, ck, payload.approvedLeave);
  knownClassVersions[ck] = Math.max(knownClassVersions[ck]||0, payload.dataVersion || 0);
  // Only refresh this class's "known synced" cache when we just replaced it wholesale —
  // if local edits were kept (the gbUnsavedChanges branch above), this class must stay
  // flagged dirty so the next Save still pushes it.
  if(replacedWholesale){
    lastSyncedClassJson[ck] = JSON.stringify(buildAllClassSlices()[ck] || { students:[], scores:{}, attendance:{}, approvedLeave:{} });
  }
  try{
    localStorage.setItem(LS_KEY, JSON.stringify({
      students, scores, studentIdCounter, attendance, approvedLeave,
      savedAt: new Date().toISOString()
    }));
  }catch(err){ /* localStorage full أو محظور - لا مشكلة */ }
  refreshUIAfterRemoteChange();
  fbApplyingRemote = false;
  // gbUnsavedChanges is deliberately left untouched here: if this device had
  // pending local edits, the merge above kept them in memory and they still
  // need their own Save press; if it didn't, it was already false.
}

// ---- applyMetaPayload(): activityLog/config/studentIdCounter/etc. — the document
// written by pushMetaDoc(). No longer touches students/scores/attendance/approvedLeave
// (see applyClassPayload above), teachers, or users at all.
function applyMetaPayload(payload){
  if(!payload) return;
  fbApplyingRemote = true;
  studentIdCounter = Math.max(payload.studentIdCounter || 1, studentIdCounter || 1);
  grade3FlexibleMaximaBySubject = gbUnsavedChanges
    ? mergeObjectField(payload.grade3FlexibleMaxima, grade3FlexibleMaximaBySubject)
    : (payload.grade3FlexibleMaxima || grade3FlexibleMaximaBySubject || {});
  try{ localStorage.setItem(GRADE3_MAXIMA_LS_KEY, JSON.stringify(grade3FlexibleMaximaBySubject)); }catch(err){}
  knownMetaVersion = Math.max(knownMetaVersion, payload.dataVersion || 0);
  if(Array.isArray(payload.activityLog) && payload.activityLog.length){
    const map = {};
    activityLog.forEach(e=> map[e.id]=e);
    payload.activityLog.forEach(e=> map[e.id]=e);
    activityLog = Object.values(map).sort((a,b)=> b.ts-a.ts).slice(0, ACTIVITY_LOG_MAX);
    saveActivityLogLocalOnly();
  }
  if(Array.isArray(payload.gradeChangeHistory)) gradeChangeHistory = mergeGradeHistory(payload.gradeChangeHistory, gradeChangeHistory);
  if(Array.isArray(payload.scheduledReports)) scheduledReports = mergeScheduledReports(payload.scheduledReports, scheduledReports);
  if(payload.termMonthDates && payload.termMonthDates.term1 && payload.termMonthDates.term2){
    termMonthDates = normalizeTermMonthDates(payload.termMonthDates);
    saveTermMonthDatesLocalOnly();
  }
  if(payload.examSchedules && payload.examSchedules.term1 && payload.examSchedules.term2){
    examSchedules = normalizeExamSchedules(payload.examSchedules);
    saveExamSchedulesLocalOnly();
  }
  if(payload.examSeatAssignments && payload.examSeatAssignments.term1 && payload.examSeatAssignments.term2){
    examSeatAssignments = normalizeExamSeatAssignments(payload.examSeatAssignments);
    saveExamSeatAssignmentsLocalOnly();
  }
  if(payload.bellTimes){
    bellTimes = normalizeBellTimes(payload.bellTimes);
    saveBellTimesLocalOnly();
  }
  if(payload.adminStructure){
    adminStructure = normalizeAdminStructure(payload.adminStructure);
    saveAdminStructureLocalOnly();
  }
  if(Array.isArray(payload.blockedStudentIds)){
    blockedStudentIds = payload.blockedStudentIds;
    saveBlockedStudentsLocalOnly();
  }
  if(payload.gradeEntryLockRules || payload.gradeEntryLockConfig){
    gradeEntryLockRules = gradeEntryLockRulesFromPayload(payload) || [];
    saveGradeEntryLockConfigLocalOnly();
  }
  if(payload.presenceBucket && !presenceBucket){
    presenceBucket = payload.presenceBucket;
    try{ localStorage.setItem(PRESENCE_BUCKET_LS_KEY, presenceBucket); }catch(err){}
  }
  if(Array.isArray(payload.reportCardReleases)){
    reportCardReleases = payload.reportCardReleases;
    saveReportCardReleases();
  }
  if(Array.isArray(payload.examScheduleReleases)){
    examScheduleReleases = payload.examScheduleReleases;
    saveExamScheduleReleasesLocalOnly();
  }
  refreshUIAfterRemoteChange();
  fbApplyingRemote = false;
}

// ---- applyTeachersPayload(): the document written by pushTeachersDoc(). No longer
// touches students/scores/attendance/users at all.
function applyTeachersPayload(payload){
  if(!payload) return;
  fbApplyingRemote = true;
  const currentTeacherIdsAtApply = new Set(teachers.map(t=>t.id));
  deletedTeacherIds = Array.from(new Set([...(payload.deletedTeacherIds||[]), ...deletedTeacherIds]))
    .filter(id => !currentTeacherIdsAtApply.has(id));
  // SAFETY GUARD (mirrors the one in pushTeachersDoc): if the incoming snapshot's teachers
  // is an empty array while THIS device already holds a real, non-empty local copy, don't
  // trust it "outright" — keep the local copy and warn instead of silently wiping the screen.
  const incomingTeachersEmpty = Array.isArray(payload.teachers) && payload.teachers.length===0;
  if(incomingTeachersEmpty && teachers.length>0 && !pendingTeachersPush){
    console.warn('applyTeachersPayload: incoming teachers is empty but this device has '+teachers.length+' locally — ignoring the incoming empty list to avoid wiping the screen.');
  }else{
    teachers = pendingTeachersPush
      ? mergeArrayById(payload.teachers, teachers, 'id')
      : (Array.isArray(payload.teachers) ? payload.teachers : teachers);
  }
  teacherIdCounter = Math.max(payload.teacherIdCounter || 1, teacherIdCounter || 1);
  teachers = teachers.filter(t=> !deletedTeacherIds.includes(t.id));
  try{
    localStorage.setItem(LS_KEY, JSON.stringify(Object.assign(
      JSON.parse(localStorage.getItem(LS_KEY)||'{}'),
      { teachers, teacherIdCounter, deletedTeacherIds, savedAt: new Date().toISOString() }
    )));
  }catch(err){ /* localStorage full أو محظور - لا مشكلة */ }
  knownTeachersVersion = Math.max(knownTeachersVersion, payload.dataVersion || 0);
  // A Teacher/HOD who was already logged in before this snapshot arrived (e.g. right after
  // page load, before the very first Firestore pull completes) had their Class/Subject scope
  // computed with an empty/stale `teachers` list. Now that `teachers` has just been merged
  // in above, re-sync that scope from it and refresh the stepper so the Teacher immediately
  // sees the Classes/Subjects actually assigned to them in the database, instead of only
  // picking them up on next login.
  if(currentUser && (currentUser.role==='teacher' || currentUser.role==='hod')){
    syncTeacherScopeFromDb(currentUser);
    currentUser.effective = getEffectivePermissions(currentUser);
    sanitizeScopedState();
    if(typeof renderStepper==='function') renderStepper();
    if(typeof renderAttendanceStepper==='function') renderAttendanceStepper();
  }
  refreshUIAfterRemoteChange();
  // إعادة تصيير Manage Users فورًا إذا كانت الشاشة الحالية هي Teachers، عشان يظهر أي
  // مدرس جديد فورًا بدل ما يستنى الرندر العادي.
  if(Array.isArray(payload.teachers) && payload.teachers.length > 0 && currentView === 'teachers'){
    setTimeout(() => { if(typeof renderTeachersDatabase === 'function') renderTeachersDatabase(); }, 50);
  }
  fbApplyingRemote = false;
}

// ---- applyUsersPayload(): the two documents written by pushUsersDocs() (Staff + Parents),
// merged back into the single in-memory `users` array. No longer touches
// students/scores/attendance/teachers at all.
function applyUsersPayload(staffPayload, parentPayload){
  staffPayload = staffPayload || {};
  parentPayload = parentPayload || {};
  const incomingUsers = [...(Array.isArray(staffPayload.users)?staffPayload.users:[]), ...(Array.isArray(parentPayload.users)?parentPayload.users:[])];
  const incomingDeletedUsernames = Array.from(new Set([...(staffPayload.deletedUsernames||[]), ...(parentPayload.deletedUsernames||[])]));
  if(!incomingUsers.length && !incomingDeletedUsernames.length) return;
  fbApplyingRemote = true;
  // Same fix as deletedTeacherIds above, and the direct cause of the reported bug: a
  // username currently present in our own in-memory `users` (just added/re-imported on this
  // device) is excluded from the merged tombstone list instead of being unioned in from the
  // server's copy. Otherwise a tombstone from ANY earlier, unrelated deletion would keep
  // silently stripping a freshly re-added username back out forever.
  const currentUsernamesAtApply = new Set(users.map(u=>u.username));
  deletedUsernames = Array.from(new Set([...incomingDeletedUsernames, ...deletedUsernames]))
    .filter(u => !currentUsernamesAtApply.has(u));
  // SAFETY GUARD, same as teachers above: an empty incoming combined list while this
  // device already has real local users is far more likely a corrupted write than 200
  // legitimate deletions at once — keep the local copy and warn instead of wiping it.
  if(incomingUsers.length===0 && users.length>0 && !pendingUsersPush){
    console.warn('applyUsersPayload: incoming users is empty but this device has '+users.length+' locally — ignoring the incoming empty list to avoid wiping the screen.');
  }else if(incomingUsers.length){
    users = usersUnsavedChanges
      ? mergeArrayById(incomingUsers, users, 'username').filter(u=> !deletedUsernames.includes(u.username))
      : incomingUsers.filter(u=> !deletedUsernames.includes(u.username));
    saveUsersLocalOnly();
  }
  knownStaffUsersVersion = Math.max(knownStaffUsersVersion, staffPayload.dataVersion || 0);
  knownParentUsersVersion = Math.max(knownParentUsersVersion, parentPayload.dataVersion || 0);
  // A Parent/Student account has the same staleness problem as Teacher/HOD above, just via
  // `users` instead of `teachers`: currentUser.effective (specifically .studentScope) is only
  // ever computed once, at login — see loginAs(). If that account was already open in a
  // browser tab when an Admin links it to a student (or adds a sibling) from another device,
  // this snapshot merges the new studentIds into `users` above, but without the block below
  // the already-open tab kept using its original effective permissions for the rest of the
  // session, with no error and no indication anything was wrong.
  if(currentUser && currentUser.role==='parent'){
    currentUser.effective = getEffectivePermissions(currentUser);
    sanitizeScopedState();
    if(typeof renderStepper==='function') renderStepper();
    if(typeof renderAttendanceStepper==='function') renderAttendanceStepper();
    if(typeof autoSelectDashboardChildForParent==='function') autoSelectDashboardChildForParent();
    if(typeof renderDashboard==='function') renderDashboard();
    if(typeof renderCertReportsStepper==='function') renderCertReportsStepper();
    if(typeof renderCertReportsWorkspace==='function') renderCertReportsWorkspace();
  }
  refreshUIAfterRemoteChange();
  fbApplyingRemote = false;
}

/* One-off pull — used for the manual "Pull Latest" button and the initial load before the
   live listener takes over. Fetches the meta doc, every class document, and the
   teachers/users documents. */
async function pullFromGithub(silent){
  setSyncStatus('syncing');
  try{
    const [metaSnap, classesSnap, teachersSnap, staffSnap, parentSnap] = await Promise.all([
      FB_META_DOC_REF.get(), FB_CLASSES_COL.get(), FB_TEACHERS_DOC_REF.get(), FB_STAFF_USERS_DOC_REF.get(), FB_PARENT_USERS_DOC_REF.get()
    ]);
    if(metaSnap.exists) applyMetaPayload(metaSnap.data());
    classesSnap.forEach(doc=>{
      const data = doc.data();
      // The class's own classKey isn't stored inside the document itself — it's recovered
      // from the doc id (classDocId() swaps "|" for "__" to build it).
      const ck = doc.id.replace(/__/g, '|');
      applyClassPayload(ck, data);
    });
    if(teachersSnap.exists) applyTeachersPayload(teachersSnap.data());
    if(staffSnap.exists || parentSnap.exists){
      applyUsersPayload(staffSnap.exists ? staffSnap.data() : null, parentSnap.exists ? parentSnap.data() : null);
    }
    if(!metaSnap.exists && classesSnap.empty && !teachersSnap.exists && !staffSnap.exists && !parentSnap.exists){ setSyncStatus('idle'); return false; }
    setSyncStatus('synced');
    return true;
  }catch(err){
    console.warn('Firebase pull failed', err);
    setSyncStatus('error');
    if(!silent) alert('Could not fetch data from Firebase. Please check your internet connection and Firestore security rules.');
    return false;
  }
}

/* Live listeners: any browser's write to any of the three documents shows up here within
   moments, with no manual pull needed. One independent listener per document — a Teacher
   edit only ever fires the teachers listener, never touching Students/Users in memory. */
function startFirebaseLiveSync(){
  if(fbUnsubscribe) return;
  const unsubMeta = FB_META_DOC_REF.onSnapshot(snap=>{
    if(!snap.exists) return;
    const data = snap.data();
    const incomingVersion = data.dataVersion || 0;
    if(incomingVersion>0 && incomingVersion<=knownMetaVersion) return;
    if(Date.now() - fbLastPushedAt < 1500) return;
    applyMetaPayload(data);
    setSyncStatus('synced');
  }, err=>{ console.warn('Firebase live sync error (meta)', err); setSyncStatus('error'); });

  // Collection-level listener: Firestore only sends the docs that actually changed since
  // the last snapshot (snap.docChanges()), not every class every time — so this stays
  // cheap regardless of how many classes exist, the same way the old single onSnapshot
  // only ever fired when something in that one big document changed.
  const unsubClasses = FB_CLASSES_COL.onSnapshot(snap=>{
    snap.docChanges().forEach(change=>{
      if(change.type==='removed') return;
      const data = change.doc.data();
      const ck = change.doc.id.replace(/__/g, '|');
      const incomingVersion = data.dataVersion || 0;
      if(incomingVersion>0 && incomingVersion<=(knownClassVersions[ck]||0)) return;
      if(Date.now() - fbLastPushedAt < 1500) return;
      applyClassPayload(ck, data);
      setSyncStatus('synced');
    });
  }, err=>{ console.warn('Firebase live sync error (classes)', err); setSyncStatus('error'); });

  const unsubTeachers = FB_TEACHERS_DOC_REF.onSnapshot(snap=>{
    if(!snap.exists) return;
    const data = snap.data();
    const incomingVersion = data.dataVersion || 0;
    if(incomingVersion>0 && incomingVersion<=knownTeachersVersion) return;
    if(Date.now() - fbLastPushedAt < 1500) return;
    const teachersCountBefore = teachers.length;
    applyTeachersPayload(data);
    const teachersCountAfter = teachers.length;
    if(currentView === 'teachers' && teachersCountBefore !== teachersCountAfter){
      setTimeout(() => { if(typeof renderTeachersDatabase === 'function') renderTeachersDatabase(); }, 100);
    }
    setSyncStatus('synced');
  }, err=>{ console.warn('Firebase live sync error (teachers)', err); setSyncStatus('error'); });

  let latestStaffData = null, latestParentData = null;
  const applyUsersIfReady = ()=>{
    if(latestStaffData===null && latestParentData===null) return;
    applyUsersPayload(latestStaffData, latestParentData);
    setSyncStatus('synced');
  };
  const unsubStaff = FB_STAFF_USERS_DOC_REF.onSnapshot(snap=>{
    if(!snap.exists) return;
    const data = snap.data();
    const incomingVersion = data.dataVersion || 0;
    if(incomingVersion>0 && incomingVersion<=knownStaffUsersVersion) return;
    if(Date.now() - fbLastPushedAt < 1500) return;
    latestStaffData = data;
    applyUsersIfReady();
  }, err=>{ console.warn('Firebase live sync error (staff users)', err); setSyncStatus('error'); });
  const unsubParent = FB_PARENT_USERS_DOC_REF.onSnapshot(snap=>{
    if(!snap.exists) return;
    const data = snap.data();
    const incomingVersion = data.dataVersion || 0;
    if(incomingVersion>0 && incomingVersion<=knownParentUsersVersion) return;
    if(Date.now() - fbLastPushedAt < 1500) return;
    latestParentData = data;
    applyUsersIfReady();
  }, err=>{ console.warn('Firebase live sync error (parent users)', err); setSyncStatus('error'); });

  fbUnsubscribe = ()=>{ unsubMeta(); unsubClasses(); unsubTeachers(); unsubStaff(); unsubParent(); };
}
function stopFirebaseLiveSync(){
  if(fbUnsubscribe){ fbUnsubscribe(); fbUnsubscribe = null; }
}

/* ================== ONE-TIME MIGRATION: single doc -> per-class docs ==================
   Splits whatever is currently saved in the OLD 'gradebook/main' document into the new
   'gradebook/meta' document plus one 'gradebook_classes/<classId>' document per class. Run
   this exactly ONCE, by the Admin, after taking a Full Backup — see runMigrationToClassDocs()
   below. The old document is never deleted, so it remains a safety-net copy regardless.
   Guarded by a `migratedToClassDocs` flag written into the new meta doc, so re-running this
   later (e.g. if the button is accidentally clicked twice) refuses to overwrite newer
   per-class data with a stale full-doc snapshot. */
async function runMigrationToClassDocs(){
  if(!currentUser || currentUser.role!=='admin'){
    alert('Only the Admin account can run this migration.');
    return;
  }
  if(!confirm('This is a one-time step that splits the old single Firestore document into one document per class, so the Save button only has to sync the class you actually edited instead of the whole school every time.\n\nMake sure you have already taken a Full Backup from Configuration before continuing.\n\nContinue with the migration now?')){
    return;
  }
  try{
    const metaSnap = await FB_META_DOC_REF.get();
    if(metaSnap.exists && metaSnap.data().migratedToClassDocs){
      alert('This migration has already been completed — nothing more to do.');
      hideMigrationButton();
      return;
    }
    const mainSnap = await FB_DOC_REF.get();
    if(!mainSnap.exists){
      alert('No old data was found on Firestore to migrate — nothing to do. (This is expected if the app has never been synced before.)');
      return;
    }
    const old = mainSnap.data() || {};
    const oldStudents = old.students || {};
    const oldScores = old.scores || {};
    const oldAttendance = old.attendance || {};
    const oldApprovedLeave = old.approvedLeave || {};
    const allClassKeys = new Set([
      ...Object.keys(oldStudents),
      ...Object.keys(oldScores).map(classKeyOfDataKey),
      ...Object.keys(oldAttendance).map(classKeyOfDataKey),
      ...Object.keys(oldApprovedLeave).map(classKeyOfDataKey)
    ]);
    let written = 0;
    for(const ck of allClassKeys){
      if(!ck) continue;
      const slice = { students: oldStudents[ck] || [], scores:{}, attendance:{}, approvedLeave:{} };
      Object.keys(oldScores).forEach(k=>{ if(classKeyOfDataKey(k)===ck) slice.scores[k] = oldScores[k]; });
      Object.keys(oldAttendance).forEach(k=>{ if(classKeyOfDataKey(k)===ck) slice.attendance[k] = oldAttendance[k]; });
      Object.keys(oldApprovedLeave).forEach(k=>{ if(classKeyOfDataKey(k)===ck) slice.approvedLeave[k] = oldApprovedLeave[k]; });
      await classDocRef(ck).set(Object.assign({}, slice, { dataVersion: 1, savedAt: new Date().toISOString() }));
      written++;
    }
    await FB_META_DOC_REF.set({
      studentIdCounter: old.studentIdCounter || 1,
      activityLog: old.activityLog || [],
      termMonthDates: old.termMonthDates || null,
      examSchedules: old.examSchedules || null,
      examSeatAssignments: old.examSeatAssignments || null,
      bellTimes: old.bellTimes || null,
      adminStructure: old.adminStructure || null,
      blockedStudentIds: old.blockedStudentIds || [],
      grade3FlexibleMaxima: old.grade3FlexibleMaxima || {},
      gradeEntryLockRules: old.gradeEntryLockRules || [],
      presenceBucket: old.presenceBucket || null,
      reportCardReleases: old.reportCardReleases || [],
      examScheduleReleases: old.examScheduleReleases || [],
      dataVersion: 1,
      savedAt: new Date().toISOString(),
      migratedToClassDocs: true
    });
    alert(`Migration complete — ${written} class document(s) were created. The old document was left untouched as a backup copy. The page will now reload to load the new structure.`);
    location.reload();
  }catch(err){
    console.error('Migration to per-class documents failed', err);
    alert('Migration failed — check the browser console for details. Nothing was deleted, so it is safe to try again once the problem is fixed (e.g. a Firestore rules or connection issue).');
  }
}

let migrationButtonChecked = false;
function hideMigrationButton(){
  const el = document.getElementById('migrateClassDocsBtn');
  if(el) el.remove();
}
// Shows a small floating one-time button for the Admin only, and only until the migration
// above has actually been completed (tracked by the meta doc's migratedToClassDocs flag) —
// it removes itself permanently from the UI the moment that flag is set.
async function maybeShowMigrationButton(){
  if(!currentUser || currentUser.role!=='admin') return;
  try{
    const metaSnap = await FB_META_DOC_REF.get();
    if(metaSnap.exists && metaSnap.data().migratedToClassDocs){ migrationButtonChecked = true; hideMigrationButton(); return; }
  }catch(err){ return; } // offline/no permissions yet — just skip silently, will check again next login
  migrationButtonChecked = true;
  if(document.getElementById('migrateClassDocsBtn')) return;
  const btn = document.createElement('button');
  btn.id = 'migrateClassDocsBtn';
  btn.textContent = '⚙️ Migrate Firestore Storage (one-time)';
  btn.title = 'One-time: split the old single Firestore document into one document per class, so Save only syncs the class you edited.';
  btn.style.cssText = 'position:fixed;bottom:16px;left:16px;z-index:9999;padding:10px 14px;border-radius:8px;border:1px solid #b5791b;background:#FBF0DC;color:#8a5a10;font-size:13px;font-weight:600;cursor:pointer;box-shadow:0 2px 8px rgba(0,0,0,.15);';
  btn.onclick = runMigrationToClassDocs;
  document.body.appendChild(btn);
}

// Pushes the meta document only (Bell Times, Admin Structure, Exam Schedules, Blocked
// Students, Releases, activity log, etc.) — Teachers and Users each have their own push
// path below and never go through this function. Grade Book data (students/scores/
// attendance/approvedLeave) is pushed separately, per-class, only via the Grade Book's own
// manual Save button (see pushGradeBookToFirestore/pushDirtyClassDocsWithRetry above).
async function pushToGithub(){
  if(!githubReady()) return false;
  setSyncStatus('syncing');
  const ok = await pushMetaDocWithRetry();
  setSyncStatus(ok ? 'synced' : 'error');
  if(ok) pendingFirestorePush = false; // this device's memory now matches the server — safe to close/reload
  return ok;
}

let githubPushTimer = null;
function scheduleGithubPush(){
  if(!githubReady() || fbApplyingRemote) return; // don't echo back a change we just received
  pendingFirestorePush = true; // there is now an edit sitting only in memory until the debounced push below lands
  clearTimeout(githubPushTimer);
  githubPushTimer = setTimeout(()=>{
    pushToGithub().then(ok=>{
      showGbToast(ok ? 'success' : 'error', ok ? '✓ Saved' : '✕ Save failed — check your internet connection');
    });
  }, 1000);
}

// Teachers Database's own debounced push — completely independent of the main doc/users
// pushes above and below. Adding/editing/deleting a Teacher only ever goes through this path.
let teachersPushTimer = null;
function scheduleTeachersPush(){
  if(!githubReady() || fbApplyingRemote) return;
  pendingTeachersPush = true;
  clearTimeout(teachersPushTimer);
  teachersPushTimer = setTimeout(()=>{
    pushTeachersDocWithRetry().then(ok=>{
      pendingTeachersPush = !ok;
      showGbToast(ok ? 'success' : 'error', ok ? '✓ Saved' : '✕ Save failed — check your internet connection');
    });
  }, 1000);
}

// Manage Users' own debounced push (Staff + Parents/Students documents together, split by
// role — see pushUsersDocs) — completely independent of the main doc/teachers pushes above.
let usersPushTimer = null;
function scheduleUsersPush(){
  if(!githubReady() || fbApplyingRemote) return;
  pendingUsersPush = true;
  clearTimeout(usersPushTimer);
  usersPushTimer = setTimeout(()=>{
    pushUsersDocsWithRetry().then(ok=>{
      // A successful push means whatever local `users` edit triggered it (see saveUsers())
      // has now actually reached Firestore — from this point on, the next incoming
      // snapshot's copy of `users` is at least as fresh as ours, so it's safe to trust it
      // fully again instead of defensively preferring our local copy.
      if(ok) usersUnsavedChanges = false;
      pendingUsersPush = !ok;
      showGbToast(ok ? 'success' : 'error', ok ? '✓ Saved' : '✕ Save failed — check your internet connection');
    });
  }, 1000);
}

/* ---------- Firebase Sync modal ---------- */
function openGithubModal(){
  if(!currentUser || currentUser.role!=='admin'){ alert('Only the Admin can configure Firebase sync.'); return; }
  loadGithubConfig();
  const cfg = githubConfig || {};
  document.getElementById('fbProjectLabel').textContent = firebaseConfig.projectId || '—';
  document.getElementById('ghEnabled').checked = !!cfg.enabled;
  const lastSyncLabel = formatSyncTimeLabel(getLastSyncTime());
  const baseStatus = cfg.enabled ? 'Automatic live sync is currently ON.' : 'Automatic live sync is currently OFF.';
  document.getElementById('ghModalStatus').textContent = lastSyncLabel ? `${baseStatus} Last synced: ${lastSyncLabel}.` : baseStatus;
  document.getElementById('githubOverlay').classList.add('show');
}
function closeGithubModal(){
  document.getElementById('githubOverlay').classList.remove('show');
}
function saveGithubSettings(){
  const enabled = document.getElementById('ghEnabled').checked;
  githubConfig = { enabled };
  persistGithubConfig();
  document.getElementById('ghModalStatus').textContent = enabled ? 'Settings saved. Automatic live sync is ON.' : 'Settings saved. Automatic live sync is OFF.';
  setSyncStatus('idle');
  if(enabled){ pullFromGithub(true); startFirebaseLiveSync(); }
  else stopFirebaseLiveSync();
}
function manualPushToGithub(){
  if(!githubReady()){ alert('Please enable Firebase sync first.'); return; }
  pushToGithub().then(ok=>{
    document.getElementById('ghModalStatus').textContent = ok ? 'Pushed to Firebase successfully.' : 'Push failed — check the console/Firestore rules.';
  });
}
function manualPullFromGithub(){
  pullFromGithub(false).then(ok=>{
    const lastSyncLabel = formatSyncTimeLabel(getLastSyncTime());
    document.getElementById('ghModalStatus').textContent = ok
      ? `Latest data pulled from Firebase.${lastSyncLabel ? ' Last synced: '+lastSyncLabel+'.' : ''}`
      : 'Pull failed or no data saved yet on Firebase.';
    if(ok) applyPermissionsUI();
  });
}
function disableGithubSync(){
  if(!confirm('Disconnect Firebase sync? Auto-sync will be turned off on this device.')) return;
  githubConfig = { enabled:false };
  persistGithubConfig();
  stopFirebaseLiveSync();
  document.getElementById('ghEnabled').checked = false;
  document.getElementById('ghModalStatus').textContent = 'Firebase sync disconnected.';
  setSyncStatus('idle');
}

/* ================== ACTIVE VISITORS (PRESENCE) ==================
   There is no private server for this static site, so "who is online"
   is tracked with kvdb.io — a free, keyless, tiny key/value store used
   ONLY for presence blips (never for grades/student data). Each signed-in
   user's own browser writes its own heartbeat; every browser reads all
   heartbeats to build the "active now" list. The bucket ID itself is
   created once (by the Admin's browser) and then travels to every other
   device automatically through the normal GitHub sync payload. */
const PRESENCE_BUCKET_LS_KEY = 'gradesSystemPresenceBucket_v1';
const PRESENCE_HEARTBEAT_MS  = 25000;   // how often this browser reports itself
const PRESENCE_POLL_MS       = 30000;   // how often the widget refreshes
const PRESENCE_STALE_MS      = 70000;   // ignore heartbeats older than this
let presenceBucket = null;

try{ presenceBucket = localStorage.getItem(PRESENCE_BUCKET_LS_KEY) || null; }catch(err){}

async function ensurePresenceBucket(){
  if(presenceBucket) return presenceBucket;
  // Only the Admin auto-provisions a brand-new bucket the very first time;
  // it then reaches every other device via the existing GitHub sync payload.
  if(!currentUser || currentUser.role!=='admin') return null;
  try{
    const res = await fetch('https://kvdb.io', { method:'POST', body:'email=grade-book-presence@example.com' });
    if(!res.ok) return null;
    const id = (await res.text()).trim();
    if(!id) return null;
    presenceBucket = id;
    try{ localStorage.setItem(PRESENCE_BUCKET_LS_KEY, id); }catch(err){}
    saveState(); // piggybacks on the normal save/sync flow to share the bucket ID
    return presenceBucket;
  }catch(err){ console.warn('Could not create presence bucket', err); return null; }
}

async function sendPresenceHeartbeat(){
  if(!currentUser) return;
  const bucket = await ensurePresenceBucket();
  if(!bucket) return;
  const key = 'presence:' + encodeURIComponent(currentUser.username);
  const value = JSON.stringify({ name: currentUser.displayName || currentUser.username, role: currentUser.role, ts: Date.now() });
  try{ await fetch(`https://kvdb.io/${bucket}/${key}?ttl=90`, { method:'POST', body:value }); }
  catch(err){ /* ignore transient network errors */ }
}

async function removePresenceKey(){
  if(!currentUser || !presenceBucket) return;
  const key = 'presence:' + encodeURIComponent(currentUser.username);
  try{ await fetch(`https://kvdb.io/${presenceBucket}/${key}`, { method:'DELETE' }); }
  catch(err){ /* ignore */ }
}

async function refreshActiveVisitorsWidget(){
  const listEl = document.getElementById('activeVisitorsList');
  const countEl = document.getElementById('activeVisitorsCount');
  if(!listEl || !countEl) return;
  const bucket = presenceBucket || await ensurePresenceBucket();
  if(!bucket){ countEl.textContent = currentUser ? '1' : '0'; listEl.innerHTML = '<span class="visitor-chip-empty">Presence sync not set up yet</span>'; return; }
  try{
    const listRes = await fetch(`https://kvdb.io/${bucket}/?prefix=presence:`);
    if(!listRes.ok) throw new Error('list failed');
    const text = await listRes.text();
    const keys = text.split('\n').map(s=>s.trim()).filter(Boolean);
    const now = Date.now();
    const entries = await Promise.all(keys.map(async k=>{
      try{
        const r = await fetch(`https://kvdb.io/${bucket}/${k}`);
        if(!r.ok) return null;
        const data = JSON.parse(await r.text());
        if(!data || (now - data.ts) > PRESENCE_STALE_MS) return null;
        return data;
      }catch(err){ return null; }
    }));
    const active = entries.filter(Boolean).sort((a,b)=> (a.name||'').localeCompare(b.name||''));
    countEl.textContent = active.length;
    listEl.innerHTML = active.length
      ? active.map(u=> `<div class="visitor-chip">${escapeHtml(u.name)} <small>${escapeHtml(ROLE_LABELS[u.role] || u.role || '')}</small></div>`).join('')
      : '<span class="visitor-chip-empty">No one else online</span>';
  }catch(err){
    console.warn('Could not refresh active visitors', err);
  }
}

function startPresenceTracking(){
  sendPresenceHeartbeat();
  refreshActiveVisitorsWidget();
  refreshBirthdayWidgets();
  registerTicker('presenceHeartbeat', PRESENCE_HEARTBEAT_MS, sendPresenceHeartbeat);
  registerTicker('presenceWidget', PRESENCE_POLL_MS, refreshActiveVisitorsWidget);
  registerTicker('birthdayWidget', 10*60*1000, refreshBirthdayWidgets);
}
function stopPresenceTracking(){
  unregisterTicker('presenceHeartbeat');
  unregisterTicker('presenceWidget');
  removePresenceKey();
  const countEl = document.getElementById('activeVisitorsCount');
  const listEl = document.getElementById('activeVisitorsList');
  if(countEl) countEl.textContent = '0';
  if(listEl) listEl.innerHTML = '<span class="visitor-chip-empty">Sign in to see who\'s online</span>';
}

