// renderStepper()/renderAttendanceStepper()/renderWorkspace()/renderAttendanceWorkspace()
// used to run here unconditionally too, for the exact same reason renderDatabaseNow() and
// renderTeachersDatabase() (below) were removed from this spot: #appWrap is display:none
// until login, so building the Grade Book/Attendance stepper and workspace here is pure
// waste before login, and redundant after it — loginAs() -> switchView(allowed) now lazily
// renders only the tab the signed-in user actually lands on.
// renderDatabaseNow() and renderTeachersDatabase() used to run here unconditionally on
// every page load, building the FULL unfiltered student/teacher tables (sticky columns,
// badges, etc.) into #appWrap — which is display:none until login. That work is pure
// waste before login (nobody can see it yet) and is redundant even after login, since
// switchView() already renders each table on demand the moment its tab is actually
// opened (see the 'database'/'teachers' cases above). Removing them here noticeably
// speeds up the time the login screen becomes responsive.
renameAttendanceNavTab();
ensureApprovedLeaveNavTab();
// Renames the "Absence" nav tab button to "Absence (Subjects)" — Approved Leave used to be
// bundled into this same tab's name/dropdown, but now has its own separate nav item (built by
// ensureApprovedLeaveNavTab() above) — preserving any leading icon element inside the button
// (only the trailing text node is replaced) since the button's exact markup lives in the HTML
// file, not here.
function renameAttendanceNavTab(){
  const tab = document.getElementById('navTabAttendance');
  if(!tab) return;
  const NEW_LABEL = 'Absence (Subjects)';
  let textNode = null;
  for(let i=tab.childNodes.length-1; i>=0; i--){
    const n = tab.childNodes[i];
    if(n.nodeType===3 && n.textContent.trim()){ textNode = n; break; }
  }
  if(textNode) textNode.textContent = (textNode.textContent.match(/^\s*/)||[''])[0] + NEW_LABEL;
  else tab.textContent = NEW_LABEL;
  tab.title = NEW_LABEL;
}
/* ================== DATE / TIME / WEATHER WIDGET ================== */
function dtwUpdateClock(){
  const now = new Date();
  const hh = String(now.getHours()).padStart(2,'0');
  const mm = String(now.getMinutes()).padStart(2,'0');
  const ss = String(now.getSeconds()).padStart(2,'0');
  const clockEl = document.getElementById('dtwClock');
  const dateEl = document.getElementById('dtwDate');
  if(clockEl) clockEl.textContent = `${hh}:${mm}:${ss}`;
  if(dateEl){
    dateEl.textContent = now.toLocaleDateString('en-GB', { weekday:'long', day:'numeric', month:'long', year:'numeric' });
  }
}

const DTW_WEATHER_CODES = {
  0:  ['☀️','Clear sky'],
  1:  ['🌤️','Mostly clear'],
  2:  ['⛅','Partly cloudy'],
  3:  ['☁️','Overcast'],
  45: ['🌫️','Fog'],
  48: ['🌫️','Fog'],
  51: ['🌦️','Light drizzle'],
  53: ['🌦️','Drizzle'],
  55: ['🌦️','Dense drizzle'],
  61: ['🌧️','Light rain'],
  63: ['🌧️','Rain'],
  65: ['🌧️','Heavy rain'],
  71: ['❄️','Light snow'],
  73: ['❄️','Snow'],
  75: ['❄️','Heavy snow'],
  80: ['🌦️','Rain showers'],
  81: ['🌦️','Rain showers'],
  82: ['⛈️','Violent showers'],
  95: ['⛈️','Thunderstorm'],
  96: ['⛈️','Thunderstorm w/ hail'],
  99: ['⛈️','Thunderstorm w/ hail']
};

function dtwRenderWeather(tempC, code, cityLabel){
  const iconEl = document.getElementById('dtwIcon');
  const tempEl = document.getElementById('dtwTemp');
  const condEl = document.getElementById('dtwCond');
  const wrapEl = document.getElementById('dtwCityWrap');
  const info = DTW_WEATHER_CODES[code] || ['🌡️','—'];
  if(iconEl) iconEl.textContent = info[0];
  if(tempEl) tempEl.textContent = `${Math.round(tempC)}°C`;
  if(condEl) condEl.textContent = info[1];
  if(wrapEl) wrapEl.title = cityLabel || '';
}

function dtwFetchWeather(lat, lon, cityLabel){
  fetch(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true`)
    .then(r=>r.json())
    .then(data=>{
      const cw = data && data.current_weather;
      if(cw){ dtwRenderWeather(cw.temperature, cw.weathercode, cityLabel); }
      else { document.getElementById('dtwCond').textContent = 'Weather unavailable'; }
    })
    .catch(()=>{
      const condEl = document.getElementById('dtwCond');
      if(condEl) condEl.textContent = 'Weather unavailable';
    });
}

function dtwInitWeather(){
  // Default fallback: Madinaty, Cairo, Egypt
  const fallback = { lat:30.078, lon:31.617, label:'Madinaty, Cairo' };
  if(navigator.geolocation){
    navigator.geolocation.getCurrentPosition(
      pos => dtwFetchWeather(pos.coords.latitude, pos.coords.longitude, 'Your location'),
      () => dtwFetchWeather(fallback.lat, fallback.lon, fallback.label),
      { timeout:5000 }
    );
  } else {
    dtwFetchWeather(fallback.lat, fallback.lon, fallback.label);
  }
}

function initDateTimeWeatherWidget(){
  dtwUpdateClock();
  registerTicker('dtwClock', 1000, dtwUpdateClock);
  dtwInitWeather();
  registerTicker('dtwWeather', 30 * 60 * 1000, dtwInitWeather); // refresh weather every 30 minutes
}

